-- Generated from Quibble/Quibble/Data/QuestionBank.swift.
-- Replaces seeded Quibble topic questions with the full local MVP question bank.

begin;

on conflict (slug) do update set
  title = excluded.title,
  subtitle = excluded.subtitle,
  description = excluded.description,
  color_key = excluded.color_key,
  icon_asset_name = excluded.icon_asset_name,
  is_featured = excluded.is_featured,
  status = 'active';

delete from public.daily_challenge_questions
where daily_challenge_id in (select id from public.daily_challenges where challenge_date = current_date);

delete from public.questions
where topic_id in (select id from public.topics where slug in ('cricket', 'bollywood', 'tech', 'geography', 'food', 'history', 'music', 'fitness', 'science', 'movies'));

;

select current_date, t.id, 'Daily Challenge'
from public.topics t
where t.slug = 'cricket'
on conflict (challenge_date) do update set
  topic_id = excluded.topic_id,
  title = excluded.title,
  status = 'active';

select dc.id, q.id, row_number() over (order by q.created_at, q.id) - 1
from public.daily_challenges dc
join public.questions q on q.status = 'approved'
where dc.challenge_date = current_date
order by q.created_at, q.id
limit 7;

commit;
